+    const { verseTimings } = await chapterAudioPromise;
+    const lastVerseKey = verseTimings[verseTimings.length - 1]?.verseKey ?? verseKey;
+    return { verseKey: lastVerseKey, chapterId };
+  }
+  return fetchStopPoint(verseKey, stopPoint);
+}
